import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    return {
      scanTarget: 'EC2 Security Groups with public SSH access',
      region: input.awsRegion,
      port: input.checkPort || 22,
      vulnerability: 'Allows 0.0.0.0/0 access',
      severity: 'CRITICAL',
      status: 'ready_for_security_group_scan',
      recommendation: 'Restrict to specific IP ranges or security groups only'
    };
  } catch (error) {
    console.error('Error analyzing SSH exposure:', error);
    throw new Error(`Failed to analyze SSH exposure: ${error}`);
  }
}
